def rote_learning(episodes: list, gamma: float) -> dict:
    import numpy as np
    from collections import defaultdict

    state_returns = defaultdict(list)

    for episode in episodes:
        if not episode:
            continue
        states = [s for s, _ in episode]
        rewards = np.array([r for _, r in episode], dtype=np.float64)
        T = len(rewards)

        # gamma_powers[k] = gamma^k
        gamma_powers = gamma ** np.arange(T, dtype=np.float64)

        # G[t] = dot(gamma_powers[:T-t], rewards[t:])
        # Build via vectorized cumsum on reversed, gamma-scaled rewards
        scaled = rewards * gamma_powers          # r_t * gamma^t
        rev_cumsum = np.cumsum(scaled[::-1])[::-1]  # sum from t to T-1 of gamma^k * r_k
        returns = rev_cumsum / gamma_powers     # divide out gamma^t to get G_t

        for t, state in enumerate(states):
            state_returns[state].append(float(returns[t]))

    return {
        state: round(float(np.mean(vals)), 4)
        for state, vals in state_returns.items()
    }
